// Engenharia / Image e Media / Picture in Picture / 9:16 Shorts
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  Img,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type PipPosition = "bottom-right" | "bottom-left" | "top-right" | "top-left";

type EngineeringPictureInPictureProps = {
  mainMediaUrl?: string;
  pipMediaUrl?: string;
  mainTitle?: string;
  mainSubtitle?: string;
  pipTitle?: string;
  pipSubtitle?: string;
  pipTag?: string;
  coordinateText?: string;
  distanceText?: string;
  descriptorText?: string;
  projectCode?: string;
  statusText?: string;
  location?: string;
  panelLabel?: string;
  pipDelayFrames?: number | string;
  pipWidth?: number | string;
  pipHeight?: number | string;
  pipPosition?: PipPosition;
  pipInset?: number | string;
  showMainContentLabel?: boolean;
  showPointerLines?: boolean;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
  textColor?: string;
};

const toNumber = (value: unknown, fallback: number) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clamp = (value: number, min: number, max: number) =>
  Math.max(min, Math.min(max, value));

const CornerBrackets = () => (
  <>
    {[
      { top: 28, left: 28 },
      { top: 28, right: 28 },
      { bottom: 28, left: 28 },
      { bottom: 28, right: 28 },
    ].map((position, index) => (
      <div
        key={index}
        style={{
          position: "absolute",
          ...position,
          width: 42,
          height: 42,
          borderColor: "rgba(34,211,238,0.55)",
          borderStyle: "solid",
          borderWidth:
            index === 0
              ? "2px 0 0 2px"
              : index === 1
                ? "2px 2px 0 0"
                : index === 2
                  ? "0 0 2px 2px"
                  : "0 2px 2px 0",
          zIndex: 90,
        }}
      />
    ))}
  </>
);

export default function EngineeringPictureInPicture({
  mainMediaUrl,
  pipMediaUrl,
  mainTitle = "CONTEDO PRINCIPAL",
  mainSubtitle = "VISÃO GERAL DA OPERAÇÃO",
  pipTitle = "PIP LOCALIZAÇÃO",
  pipSubtitle = "MAPA " ROTA " SETOR",
  pipTag = "PONTO DE REFERNCIA",
  coordinateText = "2959' S " 5118' W",
  distanceText = "DISTNCIA 1.8 KM",
  descriptorText = "JANELA PIP TCNICA ATIVA",
  projectCode = "ENG-10558",
  statusText = "PICTURE IN PICTURE ATIVO",
  location = "SETOR ESTRUTURAL A-03",
  panelLabel = "PICTURE IN PICTURE",
  pipDelayFrames = 15,
  pipWidth = 360,
  pipHeight = 230,
  pipPosition = "bottom-right",
  pipInset = 44,
  showMainContentLabel = true,
  showPointerLines = true,
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
  backgroundColor = "#05070d",
  textColor = "#ffffff",
}: EngineeringPictureInPictureProps) {
  const frame = useCurrentFrame();
  const { width, height, fps } = useVideoConfig();

  const isVertical = height > width;

  const safePipDelayFrames = Math.max(0, Math.round(toNumber(pipDelayFrames, 15)));
  const safePipInset = clamp(toNumber(pipInset, 44), 20, 120);
  const safePipWidth = clamp(toNumber(pipWidth, 360), 180, 760);
  const safePipHeight = clamp(toNumber(pipHeight, 230), 120, 520);

  const pipScaleRaw = spring({
    frame: Math.max(frame - safePipDelayFrames, 0),
    fps,
    config: {
      damping: 12,
      stiffness: 100,
      mass: 0.7,
    },
  });

  const hudRaw = spring({
    frame: frame - 8,
    fps,
    config: {
      damping: 18,
      stiffness: 90,
      mass: 0.8,
    },
  });

  const contentRaw = spring({
    frame: frame - 4,
    fps,
    config: {
      damping: 16,
      stiffness: 86,
      mass: 0.8,
    },
  });

  const pipScale = clamp(pipScaleRaw, 0, 1.06);
  const hudProgress = clamp(hudRaw, 0, 1);
  const contentProgress = clamp(contentRaw, 0, 1);

  const pipOpacity = interpolate(pipScale, [0, 0.25, 1], [0, 1, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const pipTranslateY = interpolate(pipScale, [0, 1], [42, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const scanY = interpolate(frame % 130, [0, 130], [-12, 112]);
  const markerX = interpolate(frame % 120, [0, 120], [-18, 118]);

  const progressPercent = Math.round(
    interpolate(frame, [0, safePipDelayFrames + 36], [0, 100], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    })
  );

  const glowPulse = interpolate(Math.sin(frame * 0.1), [-1, 1], [0.32, 0.82]);
  const pipGlow = Math.sin(pipScale * Math.PI);
  const orbitRotation = frame * 0.42;
  const counterOrbitRotation = -frame * 0.3;

  const activePipWidth = isVertical
    ? Math.min(width * 0.72, safePipWidth)
    : Math.min(width * 0.32, safePipWidth);

  const activePipHeight = isVertical
    ? Math.min(height * 0.22, safePipHeight)
    : Math.min(height * 0.3, safePipHeight);

  const isRight = pipPosition.includes("right");
  const isBottom = pipPosition.includes("bottom");

  const pipPositionStyle = {
    left: isRight ? undefined : safePipInset,
    right: isRight ? safePipInset : undefined,
    top: isBottom ? undefined : isVertical ? 164 : safePipInset + 24,
    bottom: isBottom ? isVertical ? 132 : safePipInset : undefined,
  };

  const titleSize = isVertical
    ? Math.min(width * 0.072, 70)
    : Math.min(height * 0.078, 82);

  const subtitleSize = isVertical ? width * 0.032 : height * 0.03;
  const pipTitleSize = isVertical
    ? Math.min(width * 0.038, 34)
    : Math.min(height * 0.034, 36);
  const pipMetaSize = isVertical ? Math.min(width * 0.024, 21) : Math.min(height * 0.022, 23);
  const metaSize = isVertical ? width * 0.027 : height * 0.024;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: textColor,
        fontFamily:
          "Inter, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            radial-gradient(circle at 20% 22%, rgba(34,211,238,0.18) 0%, transparent 34%),
            radial-gradient(circle at 82% 74%, rgba(250,204,21,0.12) 0%, transparent 36%),
            linear-gradient(135deg, #05070d 0%, #071827 48%, #0f3f3d 100%)
          `,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.04) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.04) 1px, transparent 1px)
          `,
          backgroundSize: "42px 42px, 42px 42px, 168px 168px, 168px 168px",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            linear-gradient(90deg, rgba(2,6,23,0.86), transparent 18%, transparent 82%, rgba(2,6,23,0.86)),
            radial-gradient(circle at center, transparent 0%, rgba(2,6,23,0.56) 70%, rgba(0,0,0,0.92) 100%)
          `,
        }}
      />

      <svg
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          pointerEvents: "none",
          opacity: 0.52,
        }}
        viewBox={`0 0 ${width} ${height}`}
        preserveAspectRatio="none"
      >
        <circle
          cx={width * 0.5}
          cy={height * 0.5}
          r={isVertical ? width * 0.4 : height * 0.44}
          fill="none"
          stroke={primaryColor}
          strokeWidth={1.5}
          strokeDasharray="12 14"
          opacity={0.26}
        />

        <circle
          cx={width * 0.5}
          cy={height * 0.5}
          r={isVertical ? width * 0.26 : height * 0.3}
          fill="none"
          stroke={accentColor}
          strokeWidth={1.1}
          strokeDasharray="8 12"
          opacity={0.2}
        />

        <line
          x1={width * 0.1}
          y1={height * 0.5}
          x2={width * 0.9}
          y2={height * 0.5}
          stroke={primaryColor}
          strokeWidth={1}
          strokeDasharray="18 16"
          opacity={0.16}
        />

        <line
          x1={width * 0.5}
          y1={height * 0.12}
          x2={width * 0.5}
          y2={height * 0.9}
          stroke={accentColor}
          strokeWidth={1}
          strokeDasharray="14 16"
          opacity={0.12}
        />

        {Array.from({ length: 30 }).map((_, index) => {
          const angle = (index / 30) * Math.PI * 2 + frame * 0.0038;
          const outerRadius = isVertical ? width * 0.45 : height * 0.48;
          const innerRadius = outerRadius * (0.62 + pipGlow * 0.08);
          const x1 = width * 0.5 + Math.cos(angle) * innerRadius;
          const y1 = height * 0.5 + Math.sin(angle) * innerRadius;
          const x2 = width * 0.5 + Math.cos(angle) * outerRadius;
          const y2 = height * 0.5 + Math.sin(angle) * outerRadius;

          return (
            <line
              key={`picture-in-picture-axis-${index}`}
              x1={x1}
              y1={y1}
              x2={x2}
              y2={y2}
              stroke={index % 2 === 0 ? primaryColor : accentColor}
              strokeWidth={index % 4 === 0 ? 1.6 : 1}
              opacity={0.09 + contentProgress * 0.1}
            />
          );
        })}
      </svg>

      <div
        style={{
          position: "absolute",
          inset: isVertical ? "15% 7% 14%" : "13% 8% 12%",
          background: "rgba(8,13,24,0.58)",
          border: "1px solid rgba(34,211,238,0.24)",
          boxShadow: `
            0 0 ${34 + glowPulse * 32}px rgba(34,211,238,0.12),
            inset 0 0 74px rgba(34,211,238,0.06)
          `,
          clipPath:
            "polygon(0 0, calc(100% - 34px) 0, 100% 34px, 100% 100%, 34px 100%, 0 calc(100% - 34px))",
          overflow: "hidden",
          opacity: contentProgress,
          transform: `scale(${0.96 + contentProgress * 0.04})`,
          zIndex: 18,
        }}
      >
        {mainMediaUrl ? (
          <Img
            src={mainMediaUrl}
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              objectFit: "cover",
              opacity: 0.76,
              filter: "contrast(1.08) saturate(0.88)",
            }}
          />
        ) : (
          <div
            style={{
              position: "absolute",
              inset: 0,
              background: `
                radial-gradient(circle at 32% 28%, rgba(34,211,238,0.28) 0%, transparent 36%),
                radial-gradient(circle at 78% 72%, rgba(250,204,21,0.18) 0%, transparent 34%),
                linear-gradient(135deg, rgba(15,118,110,0.36), rgba(2,6,23,0.94))
              `,
            }}
          />
        )}

        <div
          style={{
            position: "absolute",
            inset: 18,
            border: "1px solid rgba(34,211,238,0.16)",
            clipPath:
              "polygon(6% 0, 94% 0, 100% 6%, 100% 94%, 94% 100%, 6% 100%, 0 94%, 0 6%)",
            zIndex: 3,
          }}
        />

        <div
          style={{
            position: "absolute",
            inset: 0,
            background: `
              radial-gradient(circle at center, transparent 0%, rgba(2,6,23,0.16) 42%, rgba(2,6,23,0.84) 100%),
              linear-gradient(135deg, rgba(34,211,238,0.08), transparent 44%, rgba(250,204,21,0.1))
            `,
            zIndex: 2,
          }}
        />

        <div
          style={{
            position: "absolute",
            inset: 0,
            backgroundImage:
              "linear-gradient(rgba(255,255,255,0.08) 1px, transparent 1px)",
            backgroundSize: "100% 7px",
            opacity: 0.18,
            mixBlendMode: "screen",
            zIndex: 4,
          }}
        />

        <div
          style={{
            position: "absolute",
            width: isVertical ? width * 0.62 : height * 0.44,
            height: isVertical ? width * 0.62 : height * 0.44,
            border: `1px solid ${primaryColor}33`,
            borderRadius: "50%",
            left: "50%",
            top: "50%",
            transform: `translate(-50%, -50%) rotate(${orbitRotation}deg)`,
            boxShadow: `0 0 34px ${primaryColor}22`,
            pointerEvents: "none",
            zIndex: 5,
          }}
        />

        <div
          style={{
            position: "absolute",
            width: isVertical ? width * 0.46 : height * 0.32,
            height: isVertical ? width * 0.46 : height * 0.32,
            border: `1px dashed ${accentColor}55`,
            borderRadius: "50%",
            left: "50%",
            top: "50%",
            transform: `translate(-50%, -50%) rotate(${counterOrbitRotation}deg)`,
            pointerEvents: "none",
            zIndex: 5,
          }}
        />

        {showMainContentLabel && (
          <div
            style={{
              position: "absolute",
              left: isVertical ? 28 : 38,
              top: isVertical ? 32 : 36,
              zIndex: 8,
              display: "inline-flex",
              alignItems: "center",
              gap: 10,
              padding: "9px 13px",
              background: "rgba(2,6,23,0.72)",
              border: `1px solid ${primaryColor}55`,
              color: primaryColor,
              fontSize: metaSize,
              fontWeight: 900,
              letterSpacing: 1.7,
              textTransform: "uppercase",
              clipPath:
                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px))",
            }}
          >
            <span
