        <div
          style={{
            position: "relative",
            marginTop: 12,
            height: 8,
            width: "100%",
            background: "rgba(255,255,255,0.09)",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              width: `${progressPercent}%`,
              height: "100%",
              background: `linear-gradient(90deg, ${secondaryColor}, ${primaryColor}, ${accentColor})`,
              boxShadow: `0 0 16px ${primaryColor}`,
            }}
