          <div
            style={{
              position: "absolute",
              left: `${markerX}%`,
              top: 0,
              bottom: 0,
              width: 3,
              background: accentColor,
              opacity: 0.6,
              boxShadow: `0 0 16px ${accentColor}`,
            }}
          />
        </div>
      </div>

      <CornerBrackets />
    </AbsoluteFill>
  );
}

